from zeep import Client, HelpRequest
from xml.dom.minidom import parseString
import sys

client = Client('http://insurance-service.com?wsdl')  # replace with your WSDL URL

def policy_lookup(policy_number, customer_name):
    operation = client.service.get_operation("PolicyLookup")  # assuming PolicyLookup is the correct operation
    request = operation.create_request()

    policy_lookup_body = """
        <PolicyLookupRequest>
            <PolicyNumber>{0}</PolicyNumber>
            <CustomerName>{1}</CustomerName>
        </PolicyLookupRequest>
    """.format(policy_number, customer_name)

    request.set_xml(parseString(policy_lookup_body).documentElement)

    response = operation.send()

    # Assuming the response is in an XML format, parse it and return the result
    if response.fault:
        return None
    else:
        return response.returnvalue

policy_number = sys.argv[1]
customer_name = sys.argv[2]
result = policy_lookup(policy_number, customer_name)
print(result)